import { appApiPath } from './paths';
import type { HttpClient } from '../http/client';
import type { QueryParams } from '../types/common';
import type { BillingPreflightForm, PlusApiResultBillingPrecheckResult, PlusApiResultBillingPreholdResult, PlusApiResultBillingQuote } from '../types';


export class BillingApi {
  private client: HttpClient;
  
  constructor(client: HttpClient) { 
    this.client = client; 
  }

/** 预扣结算 */
  async settle(requestNo: string | number, params?: QueryParams): Promise<PlusApiResultBillingPreholdResult> {
    return this.client.post<PlusApiResultBillingPreholdResult>(appApiPath(`/billing/settle/${requestNo}`), undefined, params);
  }

/** 预扣释放 */
  async release(requestNo: string | number, params?: QueryParams): Promise<PlusApiResultBillingPreholdResult> {
    return this.client.post<PlusApiResultBillingPreholdResult>(appApiPath(`/billing/release/${requestNo}`), undefined, params);
  }

/** 预扣冻结 */
  async prehold(body: BillingPreflightForm): Promise<PlusApiResultBillingPreholdResult> {
    return this.client.post<PlusApiResultBillingPreholdResult>(appApiPath(`/billing/prehold`), body);
  }

/** 余额预校验 */
  async precheck(body: BillingPreflightForm): Promise<PlusApiResultBillingPrecheckResult> {
    return this.client.post<PlusApiResultBillingPrecheckResult>(appApiPath(`/billing/precheck`), body);
  }

/** 调用前报价 */
  async estimate(body: BillingPreflightForm): Promise<PlusApiResultBillingQuote> {
    return this.client.post<PlusApiResultBillingQuote>(appApiPath(`/billing/estimate`), body);
  }
}

export function createBillingApi(client: HttpClient): BillingApi {
  return new BillingApi(client);
}
