import { appApiPath } from './paths';
import type { HttpClient } from '../http/client';
import type { QueryParams } from '../types/common';
import type { EmailReadUpdateForm, EmailReceiveForm, EmailSendForm, EmailSyncForm, PlusApiResultEmailAccountConfigVO, PlusApiResultEmailMessagePageVO, PlusApiResultEmailMessageVO, PlusApiResultEmailSendResultVO, PlusApiResultEmailSyncResultVO, PlusApiResultVoid } from '../types';


export class EmailApi {
  private client: HttpClient;
  
  constructor(client: HttpClient) { 
    this.client = client; 
  }

/** Manual IMAP sync */
  async sync(body?: EmailSyncForm): Promise<PlusApiResultEmailSyncResultVO> {
    return this.client.post<PlusApiResultEmailSyncResultVO>(appApiPath(`/email/sync`), body);
  }

/** Send email */
  async send(body: EmailSendForm): Promise<PlusApiResultEmailSendResultVO> {
    return this.client.post<PlusApiResultEmailSendResultVO>(appApiPath(`/email/send`), body);
  }

/** Receive email */
  async receive(body: EmailReceiveForm): Promise<PlusApiResultEmailMessageVO> {
    return this.client.post<PlusApiResultEmailMessageVO>(appApiPath(`/email/receive`), body);
  }

/** Mark read/unread */
  async markRead(messageId: string | number, body?: EmailReadUpdateForm): Promise<PlusApiResultEmailMessageVO> {
    return this.client.post<PlusApiResultEmailMessageVO>(appApiPath(`/email/messages/${messageId}/read`), body);
  }

/** List emails */
  async listMessages(params?: QueryParams): Promise<PlusApiResultEmailMessagePageVO> {
    return this.client.get<PlusApiResultEmailMessagePageVO>(appApiPath(`/email/messages`), params);
  }

/** Get email message detail */
  async getMessage(messageId: string | number): Promise<PlusApiResultEmailMessageVO> {
    return this.client.get<PlusApiResultEmailMessageVO>(appApiPath(`/email/messages/${messageId}`));
  }

/** Delete message */
  async deleteMessage(messageId: string | number): Promise<PlusApiResultVoid> {
    return this.client.delete<PlusApiResultVoid>(appApiPath(`/email/messages/${messageId}`));
  }

/** Get SaaS managed email account config */
  async getAccountConfig(): Promise<PlusApiResultEmailAccountConfigVO> {
    return this.client.get<PlusApiResultEmailAccountConfigVO>(appApiPath(`/email/account`));
  }
}

export function createEmailApi(client: HttpClient): EmailApi {
  return new EmailApi(client);
}
