import { appApiPath } from './paths';
import type { HttpClient } from '../http/client';
import type { QueryParams } from '../types/common';
import type { OrderingCancelOrderInput, OrderingCreateOrderInput, OrderingPreviewOrderInput, PlusApiResultListOrderingCategoryOutput, PlusApiResultListOrderingMenuItemOutput, PlusApiResultOrderingMenuDetailOutput, PlusApiResultOrderingOrderDetailOutput, PlusApiResultOrderingOrderPreviewOutput, PlusApiResultOrderingShopDetailOutput, PlusApiResultOrderingShopHomeOutput, PlusApiResultOrderingSubmitOrderOutput, PlusApiResultPageOrderingMenuItemOutput, PlusApiResultPageOrderingOrderSummaryOutput, PlusApiResultPageOrderingShopOutput, PlusApiResultVoid } from '../types';


export class OrderingApi {
  private client: HttpClient;
  
  constructor(client: HttpClient) { 
    this.client = client; 
  }

/** List orders */
  async getOrders(params?: QueryParams): Promise<PlusApiResultPageOrderingOrderSummaryOutput> {
    return this.client.get<PlusApiResultPageOrderingOrderSummaryOutput>(appApiPath(`/ordering/orders`), params);
  }

/** Submit order */
  async submitOrder(body: OrderingCreateOrderInput): Promise<PlusApiResultOrderingSubmitOrderOutput> {
    return this.client.post<PlusApiResultOrderingSubmitOrderOutput>(appApiPath(`/ordering/orders`), body);
  }

/** Cancel order */
  async cancelOrder(orderId: string | number, body?: OrderingCancelOrderInput): Promise<PlusApiResultVoid> {
    return this.client.post<PlusApiResultVoid>(appApiPath(`/ordering/orders/${orderId}/cancel`), body);
  }

/** Preview order */
  async previewOrder(body: OrderingPreviewOrderInput): Promise<PlusApiResultOrderingOrderPreviewOutput> {
    return this.client.post<PlusApiResultOrderingOrderPreviewOutput>(appApiPath(`/ordering/orders/preview`), body);
  }

/** Get ordering shops */
  async getShops(params?: QueryParams): Promise<PlusApiResultPageOrderingShopOutput> {
    return this.client.get<PlusApiResultPageOrderingShopOutput>(appApiPath(`/ordering/shops`), params);
  }

/** Get ordering shop detail */
  async getShopDetail(shopId: string | number): Promise<PlusApiResultOrderingShopDetailOutput> {
    return this.client.get<PlusApiResultOrderingShopDetailOutput>(appApiPath(`/ordering/shops/${shopId}`));
  }

/** Get shop menu */
  async getShopMenu(shopId: string | number, params?: QueryParams): Promise<PlusApiResultPageOrderingMenuItemOutput> {
    return this.client.get<PlusApiResultPageOrderingMenuItemOutput>(appApiPath(`/ordering/shops/${shopId}/menu`), params);
  }

/** Get shop menu detail */
  async getShopMenuDetail(shopId: string | number, productId: string | number): Promise<PlusApiResultOrderingMenuDetailOutput> {
    return this.client.get<PlusApiResultOrderingMenuDetailOutput>(appApiPath(`/ordering/shops/${shopId}/menu/${productId}`));
  }

/** Get shop hot menu */
  async getShopHotMenu(shopId: string | number, params?: QueryParams): Promise<PlusApiResultListOrderingMenuItemOutput> {
    return this.client.get<PlusApiResultListOrderingMenuItemOutput>(appApiPath(`/ordering/shops/${shopId}/menu/hot`), params);
  }

/** Get shop menu categories */
  async getShopMenuCategories(shopId: string | number): Promise<PlusApiResultListOrderingCategoryOutput> {
    return this.client.get<PlusApiResultListOrderingCategoryOutput>(appApiPath(`/ordering/shops/${shopId}/menu/categories`));
  }

/** Get shop home */
  async getShopHome(shopId: string | number, params?: QueryParams): Promise<PlusApiResultOrderingShopHomeOutput> {
    return this.client.get<PlusApiResultOrderingShopHomeOutput>(appApiPath(`/ordering/shops/${shopId}/home`), params);
  }

/** Get order detail */
  async getOrderDetail(orderId: string | number): Promise<PlusApiResultOrderingOrderDetailOutput> {
    return this.client.get<PlusApiResultOrderingOrderDetailOutput>(appApiPath(`/ordering/orders/${orderId}`));
  }

/** Get menu */
  async getMenu(params?: QueryParams): Promise<PlusApiResultPageOrderingMenuItemOutput> {
    return this.client.get<PlusApiResultPageOrderingMenuItemOutput>(appApiPath(`/ordering/menu`), params);
  }

/** Get menu detail */
  async getMenuDetail(productId: string | number): Promise<PlusApiResultOrderingMenuDetailOutput> {
    return this.client.get<PlusApiResultOrderingMenuDetailOutput>(appApiPath(`/ordering/menu/${productId}`));
  }

/** Get hot menu */
  async getHotMenu(params?: QueryParams): Promise<PlusApiResultListOrderingMenuItemOutput> {
    return this.client.get<PlusApiResultListOrderingMenuItemOutput>(appApiPath(`/ordering/menu/hot`), params);
  }

/** Get menu categories */
  async getMenuCategories(): Promise<PlusApiResultListOrderingCategoryOutput> {
    return this.client.get<PlusApiResultListOrderingCategoryOutput>(appApiPath(`/ordering/menu/categories`));
  }
}

export function createOrderingApi(client: HttpClient): OrderingApi {
  return new OrderingApi(client);
}
