import { appApiPath } from './paths';
import type { HttpClient } from '../http/client';
import type { QueryParams } from '../types/common';
import type { ClawAuthRegisterForm, ClawHeartbeatForm, ClawLoginForm, ClawRefreshTokenForm, ClawRegisterForm, ClawScheduleTaskRegisterForm, ClawTaskReportForm, PlusApiResultClawBootstrapVO, PlusApiResultClawHeartbeatVO, PlusApiResultClawInstanceVO, PlusApiResultClawLoginVO, PlusApiResultClawScheduleTaskVO, PlusApiResultClawTaskExecutionVO } from '../types';


export class ClawApi {
  private client: HttpClient;
  
  constructor(client: HttpClient) { 
    this.client = client; 
  }

/** Report claw task execution */
  async reportTask(body: ClawTaskReportForm): Promise<PlusApiResultClawTaskExecutionVO> {
    return this.client.post<PlusApiResultClawTaskExecutionVO>(appApiPath(`/claw/registry/tasks/report`), body);
  }

/** Register claw schedule task */
  async registerTask(body: ClawScheduleTaskRegisterForm): Promise<PlusApiResultClawScheduleTaskVO> {
    return this.client.post<PlusApiResultClawScheduleTaskVO>(appApiPath(`/claw/registry/tasks/register`), body);
  }

/** Register claw instance */
  async createRegister(body: ClawRegisterForm): Promise<PlusApiResultClawInstanceVO> {
    return this.client.post<PlusApiResultClawInstanceVO>(appApiPath(`/claw/registry/register`), body);
  }

/** Accept heartbeat */
  async heartbeat(body: ClawHeartbeatForm): Promise<PlusApiResultClawHeartbeatVO> {
    return this.client.post<PlusApiResultClawHeartbeatVO>(appApiPath(`/claw/registry/heartbeat`), body);
  }

/** Claw register */
  async createRegisterAuth(body: ClawAuthRegisterForm): Promise<PlusApiResultClawLoginVO> {
    return this.client.post<PlusApiResultClawLoginVO>(appApiPath(`/claw/auth/register`), body);
  }

/** Claw refresh */
  async refresh(body: ClawRefreshTokenForm): Promise<PlusApiResultClawLoginVO> {
    return this.client.post<PlusApiResultClawLoginVO>(appApiPath(`/claw/auth/refresh`), body);
  }

/** Claw login */
  async login(body: ClawLoginForm): Promise<PlusApiResultClawLoginVO> {
    return this.client.post<PlusApiResultClawLoginVO>(appApiPath(`/claw/auth/login`), body);
  }

/** Get claw bootstrap */
  async bootstrap(): Promise<PlusApiResultClawBootstrapVO> {
    return this.client.get<PlusApiResultClawBootstrapVO>(appApiPath(`/claw/registry/bootstrap`));
  }
}

export function createClawApi(client: HttpClient): ClawApi {
  return new ClawApi(client);
}
